// criando variáveis
const primeiroValor = 20;
const segundoValor = 5;
let resultado = 0;

// soma
resultado = primeiroValor + segundoValor;
console.log(`${primeiroValor} + ${segundoValor} = ${resultado}`);

// subtração
resultado = primeiroValor - segundoValor;
console.log(`${primeiroValor} - ${segundoValor} = ${resultado}`);

// multiplicação
resultado = primeiroValor * segundoValor;
console.log(`${primeiroValor} * ${segundoValor} = ${resultado}`);

// divisão
resultado = primeiroValor / segundoValor;
console.log(`${primeiroValor} / ${segundoValor} = ${resultado}`);

// módulo
resultado = primeiroValor % segundoValor;
console.log(`${primeiroValor} % ${segundoValor} = ${resultado}`);

// potência
resultado = primeiroValor ** segundoValor;
console.log(`${primeiroValor} ** ${segundoValor} = ${resultado}`);